const isTouchDevice =
  window.matchMedia("(pointer: coarse)").matches;

const shapeSortConfig = {
  tileSizePx: isTouchDevice ? 96 : 88,
  dragPaddingPx: isTouchDevice ? 24 : 12,
  snapTolerancePx: isTouchDevice ? 32 : 20,
};

